import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/installer-screen.Db0E_BrK.js";import{t as a}from"./chunks/macos-settings.e7FrcLCc.js";import{t as o}from"./chunks/updating-fabric.1C0PZ95m.js";const s=JSON.parse(`{"title":"Updating Fabric on macOS","description":"A step-by-step guide on how to update Fabric on macOS.","frontmatter":{"title":"Updating Fabric on macOS","description":"A step-by-step guide on how to update Fabric on macOS.","authors":["IMB11","modmuss50"],"next":false,"files":[]},"headers":[],"relativePath":"players/updating-fabric/macos.md","filePath":"players/updating-fabric/macos.md","lastUpdated":1768516421000}`);var c={name:`players/updating-fabric/macos.md`};function l(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Updating Fabric on macOS <a class="header-anchor" href="#h1" aria-label="Permalink to “Updating Fabric on macOS”">​</a></h1><h2 id="1-download-the-fabric-installer" tabindex="-1">1. Download the Fabric Installer <a class="header-anchor" href="#1-download-the-fabric-installer" aria-label="Permalink to “1. Download the Fabric Installer”">​</a></h2><p>Download the <code>.jar</code> version of the Fabric Installer from the <a href="https://fabricmc.net/use/" target="_blank" rel="noreferrer">Fabric Website</a>, by clicking on <code>Download installer (Universal/.JAR)</code>.</p><h2 id="2-run-the-fabric-installer" tabindex="-1">2. Run the Fabric Installer <a class="header-anchor" href="#2-run-the-fabric-installer" aria-label="Permalink to “2. Run the Fabric Installer”">​</a></h2><p>Close Minecraft and the Minecraft Launcher first before running the installer.</p><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>You may receive a warning that Apple could not verify the <code>.jar</code>. To bypass it, open System Settings &gt; Privacy &amp; Security, then click <code>Open Anyway</code>. Confirm and enter your administrator password if prompted.</p><p><img src="/assets/players/installing-fabric/macos-settings.png" alt="macOS System Settings" loading="lazy"></p></div><p>Once you open the installer, you should see a screen like this:</p><p><img src="/assets/players/installing-fabric/installer-screen.png" alt="Fabric Installer with &quot;Install&quot; highlighted" loading="lazy"></p><p>Make sure the new game version and Loader version are correct, then click <code>Install</code> to update Fabric.</p><div class="warning custom-block"><p class="custom-block-title">IMPORTANT</p><p>Make sure to uncheck &#39;Create Profile&#39; when running the installer!</p></div><h2 id="3-update-launcher-profile" tabindex="-1">3. Update Profile in the Minecraft Launcher <a class="header-anchor" href="#3-update-launcher-profile" aria-label="Permalink to “3. Update Profile in the Minecraft Launcher”">​</a></h2><p>Once installation completes, open the Minecraft Launcher. Then go to the <code>Installations</code> tab. Find your Fabric profile and open its edit screen:</p><p><img src="/assets/players/updating-fabric.png" alt="Updating Fabric Loader version in the Minecraft Launcher" loading="lazy"></p><p>Replace the version with the new version of Fabric Loader you just installed, and press <code>Save</code>.</p><h2 id="4-you-re-done" tabindex="-1">4. You&#39;re Done! <a class="header-anchor" href="#4-you-re-done" aria-label="Permalink to “4. You&#39;re Done!”">​</a></h2><p>Once you&#39;ve completed the steps you can go back to the <code>Play</code> tab, select the Fabric profile from the dropdown in the bottom-left corner and press play!</p><p>If you encounter any issues whilst following this guide, you can ask for help in the <a href="https://discord.fabricmc.net/" target="_blank" rel="noreferrer">Fabric Discord</a> in the <code>#player-support</code> channel.</p>`,17)]])}var u=r(c,[[`render`,l]]);export{s as __pageData,u as default};